import{_ as t,o as i,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"Empty State 空状态","description":"","frontmatter":{"title":"Empty State 空状态","stage":"intermediate","direction":"interaction-design","tags":["interaction-patterns","feedback","empty-state"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/03-feedback/empty-state.md","filePath":"03-interaction-design/notes/06-interaction-patterns/03-feedback/empty-state.md","lastUpdated":null}'),s={name:"03-interaction-design/notes/06-interaction-patterns/03-feedback/empty-state.md"};function n(r,a,d,o,h,p){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="empty-state-空状态" tabindex="-1">Empty State 空状态 <a class="header-anchor" href="#empty-state-空状态" aria-label="Permalink to &quot;Empty State 空状态&quot;">​</a></h1><p>Empty State 是系统已经完成必要判断后，对“当前范围没有可展示数据”给出的界面状态。空状态必须说明空的是哪个范围、为什么为空、用户是否能改变结果，以及下一步会产生什么影响。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文处理：</p><ul><li>首次使用、筛选无结果、数据已清空和权限受限的不同语义。</li><li>从接口、缓存、权限与筛选条件推导可靠空状态。</li><li>选择创建、清除筛选、恢复、申请权限或返回等动作。</li><li>让动态零结果对辅助技术可感知。</li><li>避免把加载、错误、未授权和索引延迟误画成“没有数据”。</li></ul><p>前置知识：</p><ul><li>能定义集合范围、筛选条件和权限模型。</li><li>能区分服务器权威数据、客户端缓存和搜索索引。</li><li>理解空状态不是装饰插图，而是数据状态的结果。</li></ul><h2 id="零条记录-不足以决定界面" tabindex="-1">“零条记录”不足以决定界面 <a class="header-anchor" href="#零条记录-不足以决定界面" aria-label="Permalink to &quot;“零条记录”不足以决定界面&quot;">​</a></h2><p>相同的 <code>items.length === 0</code> 可能来自完全不同原因：</p><table tabindex="0"><thead><tr><th>原因</th><th>实际事实</th><th>合理下一步</th></tr></thead><tbody><tr><td>首次使用</td><td>范围内从未创建对象</td><td>创建、导入或了解对象</td></tr><tr><td>筛选无结果</td><td>基础集合可能有数据，当前条件无匹配</td><td>清除或修改筛选</td></tr><tr><td>搜索无结果</td><td>查询完成且无可见匹配</td><td>改词、清除范围、浏览分类</td></tr><tr><td>用户已清空</td><td>对象曾存在，现已删除、归档或处理完</td><td>查看归档、恢复或创建</td></tr><tr><td>权限受限</td><td>对象可能存在，但当前主体不可见</td><td>申请权限或切换范围</td></tr><tr><td>上游尚未配置</td><td>当前对象依赖前置设置</td><td>完成配置</td></tr><tr><td>索引未同步</td><td>权威集合有数据，检索副本暂时无结果</td><td>显示同步状态或回退查询</td></tr><tr><td>请求失败</td><td>系统无法确认集合</td><td>错误与重试</td></tr><tr><td>仍在加载</td><td>结果尚未确定</td><td>加载反馈</td></tr></tbody></table><p>如果后端只返回空数组，前端无法可靠区分这些状态。需要额外的计数、能力和数据新鲜度契约。</p><h2 id="空状态判定模型" tabindex="-1">空状态判定模型 <a class="header-anchor" href="#空状态判定模型" aria-label="Permalink to &quot;空状态判定模型&quot;">​</a></h2><p>设：</p><ul><li><code>R</code>：请求是否成功。</li><li><code>A</code>：当前主体是否有查看该范围的能力。</li><li><code>B</code>：未应用当前筛选时，基础集合是否有可见数据。</li><li><code>M</code>：当前筛选匹配数量。</li><li><code>H</code>：是否有“曾存在后被清空”的可靠历史。</li><li><code>P</code>：是否缺少必要前置配置。</li></ul><p>判定顺序：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;查询结束&quot;] --&gt; R{&quot;请求成功？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R -- &quot;否&quot; --&gt; E[&quot;错误状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R -- &quot;是&quot; --&gt; A{&quot;可查看该范围？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A -- &quot;否&quot; --&gt; X[&quot;权限状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A -- &quot;是&quot; --&gt; P{&quot;缺少前置配置？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P -- &quot;是&quot; --&gt; U[&quot;配置前置状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P -- &quot;否&quot; --&gt; M{&quot;当前匹配数 &gt; 0？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M -- &quot;是&quot; --&gt; L[&quot;列表或内容&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M -- &quot;否&quot; --&gt; B{&quot;基础集合有数据？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- &quot;是&quot; --&gt; F[&quot;筛选或搜索无结果&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- &quot;否&quot; --&gt; H{&quot;可靠记录显示曾有数据？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H -- &quot;是&quot; --&gt; C[&quot;已清空状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H -- &quot;否&quot; --&gt; N[&quot;首次使用状态&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>权限判断先于数据存在性。否则“0 个项目”可能向无权限用户暗示组织真的没有项目，或让用户误以为需要创建重复对象。</p><h2 id="四类核心空状态" tabindex="-1">四类核心空状态 <a class="header-anchor" href="#四类核心空状态" aria-label="Permalink to &quot;四类核心空状态&quot;">​</a></h2><p>以下四类状态都表现为零条可见记录，但进入条件、主要操作和退出方式不同。</p><h3 id="首次使用" tabindex="-1">首次使用 <a class="header-anchor" href="#首次使用" aria-label="Permalink to &quot;首次使用&quot;">​</a></h3><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>当前可见范围尚未建立任何对象，且用户具备创建或导入能力。首次使用状态主要解释对象用途和建立第一份有效数据的路径。</p><p>应包含：</p><ul><li>明确范围：“这个项目还没有环境变量。”</li><li>对象带来的直接结果：“添加后，部署可从受控配置读取值。”</li><li>一个主要起步操作。</li><li>若存在导入、模板或连接外部来源，按实际优先级提供。</li><li>用户无创建权限时，不显示不可执行的主按钮。</li></ul><p>不应包含：</p><ul><li>空泛欢迎语。</li><li>与当前任务无关的功能营销。</li><li>多个同等强度操作让用户重新做产品规划。</li><li>假示例冒充真实数据。</li></ul><h3 id="创建后的退出条件" tabindex="-1">创建后的退出条件 <a class="header-anchor" href="#创建后的退出条件" aria-label="Permalink to &quot;创建后的退出条件&quot;">​</a></h3><p>创建操作成功并且权威查询可读到对象后，退出空状态。仅前端乐观插入卡片时应标记待确认；写入失败需恢复空状态并保留输入。</p><h3 id="筛选或搜索无结果" tabindex="-1">筛选或搜索无结果 <a class="header-anchor" href="#筛选或搜索无结果" aria-label="Permalink to &quot;筛选或搜索无结果&quot;">​</a></h3><h3 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>基础集合中存在当前用户可见数据，但当前条件没有匹配项。用户已经投入了查询或筛选意图，因此空状态要保留条件并帮助修正。</p><p>应显示：</p><ul><li>哪些条件造成当前范围。</li><li>“0 个匹配结果”的明确结果。</li><li>清除全部筛选，以及可选的逐项移除。</li><li>搜索词拼写或范围调整建议，但不能假装知道用户意图。</li><li>当搜索索引存在延迟时，说明结果新鲜度或提供权威浏览路径。</li></ul><p>筛选无结果不能把整个页面替换为首次使用插图；筛选控件必须留在原位。</p><h3 id="动态结果消息" tabindex="-1">动态结果消息 <a class="header-anchor" href="#动态结果消息" aria-label="Permalink to &quot;动态结果消息&quot;">​</a></h3><p>若结果在同一页面更新，没有页面导航，<code>“没有匹配结果”</code> 属于状态消息。应以可程序化方式呈现，使屏幕阅读器无需移动焦点也能获知变化。结果列表本身不是简短状态消息，仍按正常内容结构呈现。</p><h3 id="已清空或完成" tabindex="-1">已清空或完成 <a class="header-anchor" href="#已清空或完成" aria-label="Permalink to &quot;已清空或完成&quot;">​</a></h3><h3 id="定义-2" tabindex="-1">定义 <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>集合曾有数据，现因用户操作、归档、处理完成或保留策略而为空。它与首次使用的区别在于用户需要确认“刚才的对象去了哪里”。</p><p>根据业务显示：</p><ul><li>“待处理队列已清空”可以是积极完成状态。</li><li>“回收站为空”只需说明没有可恢复项目。</li><li>批量删除后说明删除范围、恢复期限与审计入口。</li><li>归档后提供“查看归档”，而不是要求重新创建。</li></ul><p>“曾存在”必须来自可靠事件或集合状态，不能仅依赖本地 <code>hasVisited</code>。清除浏览器数据或换设备后，用户仍应得到正确状态。</p><h3 id="权限受限" tabindex="-1">权限受限 <a class="header-anchor" href="#权限受限" aria-label="Permalink to &quot;权限受限&quot;">​</a></h3><h3 id="定义-3" tabindex="-1">定义 <a class="header-anchor" href="#定义-3" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>当前主体不能查看目标集合，或只能看其中一部分。权限状态不是普通空状态，不能写“暂无数据”。</p><p>可显示的信息取决于泄露风险：</p><table tabindex="0"><thead><tr><th>条件</th><th>可显示</th><th>不应显示</th></tr></thead><tbody><tr><td>用户知道组织和功能存在</td><td>功能名称、缺少的能力、申请渠道</td><td>受限对象名称与数量</td></tr><tr><td>对象存在性敏感</td><td>通用不可访问状态、返回路径</td><td>403 与 404 文案差异泄露存在性</td></tr><tr><td>可申请权限</td><td>申请对象、审批人类型、预计流程</td><td>承诺一定批准</td></tr><tr><td>角色切换可解决</td><td>当前身份与可切换范围</td><td>自动冒用更高权限</td></tr></tbody></table><p>界面隐藏不构成授权。查询、计数、搜索建议和导出都必须在服务端按当前主体过滤。</p><h2 id="数据契约" tabindex="-1">数据契约 <a class="header-anchor" href="#数据契约" aria-label="Permalink to &quot;数据契约&quot;">​</a></h2><p>一个可区分空状态的集合响应可以包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>边界</th></tr></thead><tbody><tr><td><code>items</code></td><td>当前页可见记录</td><td>经过授权和当前筛选</td></tr><tr><td><code>matching_count</code></td><td>当前筛选的可见匹配数</td><td>不能包含受限对象</td></tr><tr><td><code>base_visible_count</code></td><td>移除当前筛选后的可见数</td><td>仍受相同权限与范围约束</td></tr><tr><td><code>can_create</code></td><td>当前主体能否创建</td><td>服务端能力结果</td></tr><tr><td><code>can_import</code></td><td>能否导入</td><td>与创建可能不同</td></tr><tr><td><code>prerequisite</code></td><td>未满足的前置配置</td><td>只返回可安全披露的信息</td></tr><tr><td><code>collection_state</code></td><td>active、cleared、archived 等</td><td>来自权威业务状态</td></tr><tr><td><code>data_as_of</code></td><td>数据或索引时间</td><td>检索副本可能需要</td></tr><tr><td><code>next_cursor</code></td><td>是否还有下一页</td><td>空页不等于整个集合空</td></tr></tbody></table><p>分页请求返回空页但有前页数据，通常是游标过期、删除竞态或越界，不应切换整个集合为空。客户端需回到有效页或刷新游标。</p><h2 id="空状态内容结构" tabindex="-1">空状态内容结构 <a class="header-anchor" href="#空状态内容结构" aria-label="Permalink to &quot;空状态内容结构&quot;">​</a></h2><h3 id="标题" tabindex="-1">标题 <a class="header-anchor" href="#标题" aria-label="Permalink to &quot;标题&quot;">​</a></h3><p>标题陈述当前事实，包含必要范围：</p><ul><li>“项目 Alpha 还没有部署环境。”</li><li>“没有符合 3 个筛选条件的订单。”</li><li>“待你审核的请求已处理完。”</li><li>“你无权查看组织审计日志。”</li></ul><p>避免“这里空空如也”“暂无相关内容”等无法区分原因的句子。</p><h3 id="解释" tabindex="-1">解释 <a class="header-anchor" href="#解释" aria-label="Permalink to &quot;解释&quot;">​</a></h3><p>只说明影响下一步的原因、范围或恢复条件。若用户不需要理解内部索引、队列或权限实现，不展示内部术语。</p><h3 id="主要操作" tabindex="-1">主要操作 <a class="header-anchor" href="#主要操作" aria-label="Permalink to &quot;主要操作&quot;">​</a></h3><p>主要操作必须能改变当前空状态：</p><ul><li>首次使用：创建第一项。</li><li>筛选无结果：清除筛选。</li><li>已归档：查看归档。</li><li>缺少前置：完成配置。</li><li>权限受限：申请权限或返回。</li></ul><p>“刷新”只在数据确实可能自行出现时有效，不能作为所有空状态的默认按钮。</p><h3 id="次要入口" tabindex="-1">次要入口 <a class="header-anchor" href="#次要入口" aria-label="Permalink to &quot;次要入口&quot;">​</a></h3><p>模板、导入、文档或联系管理员可以是次要入口。若用户无法执行任何改变，提供安全返回路径即可，不用制造不可操作按钮。</p><h3 id="插图" tabindex="-1">插图 <a class="header-anchor" href="#插图" aria-label="Permalink to &quot;插图&quot;">​</a></h3><p>插图不承担状态含义，且应有空文本替代。复杂插图会推低关键信息、增加下载和本地化成本。数据密集型产品常只需标题、说明和操作。</p><h2 id="布局边界" tabindex="-1">布局边界 <a class="header-anchor" href="#布局边界" aria-label="Permalink to &quot;布局边界&quot;">​</a></h2><p>空状态放在它所代表的范围内：</p><ul><li>整页集合为空：位于页面主内容。</li><li>某一面板为空：只替换该面板内容，保留页面其他区域。</li><li>表格筛选无结果：保留表头、筛选和批量操作边界。</li><li>图表无数据：保留图表标题、时间范围和数据口径。</li><li>组合看板：各卡片独立说明，不用一个全页空状态覆盖有数据区域。</li></ul><p>空状态不能让页面标题、导航和筛选突然消失，否则用户无法判断范围。</p><h2 id="状态转换" tabindex="-1">状态转换 <a class="header-anchor" href="#状态转换" aria-label="Permalink to &quot;状态转换&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Loading</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; FirstUse: &quot;成功，基础集合为零&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; FilteredEmpty: &quot;成功，基础集合有数据但匹配为零&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Permission: &quot;无查看能力&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Content: &quot;有可见匹配&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Loading --&gt; Error: &quot;无法确认&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    FirstUse --&gt; Content: &quot;首项创建并确认&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    FilteredEmpty --&gt; Content: &quot;条件变化后有匹配&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Content --&gt; Cleared: &quot;最后一项被处理、删除或归档&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Cleared --&gt; Content: &quot;恢复或新建&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Error --&gt; Loading: &quot;重试&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>转移由权威结果驱动。加载超时不应自动进入首次使用；客户端缓存失效也不等于已清空。</p><h2 id="方案取舍" tabindex="-1">方案取舍 <a class="header-anchor" href="#方案取舍" aria-label="Permalink to &quot;方案取舍&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>适用条件</th><th>收益</th><th>风险</th></tr></thead><tbody><tr><td>行内空状态</td><td>表格、卡片或面板局部为空</td><td>保留页面上下文</td><td>空间小，文案需简洁</td></tr><tr><td>整页起步状态</td><td>核心对象首次建立</td><td>能解释起步任务</td><td>容易变成功能营销</td></tr><tr><td>示例数据</td><td>学习型工具且明确标为示例</td><td>展示结构</td><td>可能污染真实分析或被误认为数据</td></tr><tr><td>模板库</td><td>对象创建有标准起点</td><td>降低首项配置成本</td><td>模板需版本和适用范围</td></tr><tr><td>直接创建表单</td><td>首项字段少、风险低</td><td>减少一次导航</td><td>复杂表单会压迫空状态</td></tr><tr><td>权限申请</td><td>有真实审批渠道</td><td>提供可执行恢复</td><td>不应泄露对象或承诺批准</td></tr></tbody></table><h2 id="案例一-知识库的首次使用与已清空" tabindex="-1">案例一：知识库的首次使用与已清空 <a class="header-anchor" href="#案例一-知识库的首次使用与已清空" aria-label="Permalink to &quot;案例一：知识库的首次使用与已清空&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>团队知识库以空间为范围。空间所有者可以创建页面和导入 Markdown；编辑者只能创建；阅读者不能创建。页面可归档 30 天后删除。</p><p>空数组可能表示：</p><ul><li>新空间从未有页面。</li><li>所有页面已归档。</li><li>阅读者只能看到未受限页面，而当前没有可见项。</li><li>查询服务失败。</li></ul><h3 id="数据与决策" tabindex="-1">数据与决策 <a class="header-anchor" href="#数据与决策" aria-label="Permalink to &quot;数据与决策&quot;">​</a></h3><p>服务端返回可见页面、可见归档数、创建能力、导入能力和空间生命周期。界面决策：</p><ul><li>新空间所有者：标题“这个空间还没有页面”，主操作“创建页面”，次操作“导入 Markdown”。</li><li>新空间编辑者：只显示创建。</li><li>阅读者无可见页面：显示“你当前没有可访问的页面”，提供返回空间列表；不显示空间内受限页面数。</li><li>所有可见页面已归档：显示“当前页面已全部归档”，主操作“查看归档”。</li><li>请求失败：显示错误与重试，不显示首次使用。</li></ul><h3 id="创建流程" tabindex="-1">创建流程 <a class="header-anchor" href="#创建流程" aria-label="Permalink to &quot;创建流程&quot;">​</a></h3><p>点击创建后进入具有稳定 URL 的编辑器。保存成功且查询能读到新页面后，列表退出空状态。若保存失败，编辑器保留标题与正文；不能回到空状态并丢失草稿。</p><p>导入完成但索引尚未更新时，空间使用权威列表读取或显示同步状态，不要先显示“导入成功”又立即回到“没有页面”。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>三种角色分别进入全新空间。</li><li>归档最后一页，确认转为“已全部归档”而非首次使用。</li><li>让导入成功但搜索索引延迟，检查列表与搜索状态。</li><li>让权限在页面打开期间被撤销。</li><li>使用键盘完成创建并返回，焦点进入新页面标题。</li><li>确认装饰插图不产生冗余朗读。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若客户端用 <code>localStorage.hasCreatedPage</code> 判断已清空，换设备后会回到首次使用，且多人协作时状态不一致。历史语义应来自空间事件或权威集合状态，不来自单个浏览器。</p><h2 id="案例二-订单筛选无结果" tabindex="-1">案例二：订单筛选无结果 <a class="header-anchor" href="#案例二-订单筛选无结果" aria-label="Permalink to &quot;案例二：订单筛选无结果&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>订单页有状态、渠道、日期和金额筛选。基础集合有 48,000 条可见订单；用户选择“已退款、线下、过去 7 天、金额大于 5,000 元”后无结果。</p><h3 id="界面" tabindex="-1">界面 <a class="header-anchor" href="#界面" aria-label="Permalink to &quot;界面&quot;">​</a></h3><p>表格标题、筛选条、已选条件和表头保持可见。表体显示：</p><ul><li>“没有符合当前 4 个条件的订单。”</li><li>主操作“清除全部筛选”。</li><li>每个筛选 Chip 可单独移除。</li><li>日期范围明确显示，避免用户忘记时区与边界。</li></ul><p>不显示“创建订单”，因为当前空只由筛选造成。也不自动扩大日期范围，这会改变用户查询而不告知。</p><h3 id="动态更新" tabindex="-1">动态更新 <a class="header-anchor" href="#动态更新" aria-label="Permalink to &quot;动态更新&quot;">​</a></h3><p>每次条件变化生成查询身份。旧响应晚到不能覆盖新条件。结果为零时，一条状态消息宣布完整语义，例如“没有符合当前筛选的订单”；随后焦点仍留在刚操作的筛选控件。</p><p>URL 保存非敏感筛选，以支持刷新和分享。包含客户姓名等敏感条件时，根据产品安全策略决定是否进入 URL。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>逐项移除筛选，确认何时出现结果。</li><li>快速改变日期和状态，制造响应乱序。</li><li>在下一页删除最后几条数据，检查空页恢复到有效页。</li><li>让查询超时，确认不会显示零结果。</li><li>屏幕阅读器能获知结果从 12 条变为 0 条，且不会把整个表格逐项播报。</li><li>320 CSS px 下筛选条件和清除操作仍可访问。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果 <code>base_visible_count</code> 由未授权的全组织总数计算，界面可能告诉低权限用户“有 48,000 条订单但你当前没有匹配”，泄露规模。基础计数必须在相同主体、组织范围和权限过滤后计算。</p><h2 id="案例三-审计日志的权限状态" tabindex="-1">案例三：审计日志的权限状态 <a class="header-anchor" href="#案例三-审计日志的权限状态" aria-label="Permalink to &quot;案例三：审计日志的权限状态&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>审计日志仅组织所有者和合规角色可见。普通管理员能看到“审计日志”功能名称，但不能读取事件；存在性和事件数量敏感。</p><h3 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h3><p>普通管理员进入后显示“你无权查看组织审计日志”，说明需要“查看审计日志”能力，并提供组织内既定申请流程。界面不显示零事件、不显示最后更新时间，也不先请求日志后由前端丢弃。</p><p>服务端可根据隐藏存在性的安全策略，对直接资源请求返回 404；产品内已知功能入口则可显示通用权限页面。HTTP 状态与用户文案都必须服从泄露模型，不能仅为了视觉统一伪造 200 空数组。</p><h3 id="验证-2" tabindex="-1">验证 <a class="header-anchor" href="#验证-2" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>直接 URL、导航、搜索建议和浏览器缓存使用同一权限结果。</li><li>权限授予后重新查询，进入真实列表或真实首次空状态。</li><li>权限撤销后清除缓存数据，页面不短暂显示旧日志。</li><li>申请权限操作记录目标能力，不包含敏感日志内容。</li></ul><h3 id="失败分支-2" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-2" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若前端先收到全部日志再隐藏表格，网络响应、缓存和分析脚本都可能泄露数据。空状态设计不能修复授权架构；服务端必须先过滤或拒绝。</p><h2 id="无障碍与状态消息" tabindex="-1">无障碍与状态消息 <a class="header-anchor" href="#无障碍与状态消息" aria-label="Permalink to &quot;无障碍与状态消息&quot;">​</a></h2><ul><li>空状态使用正常标题、段落和真实按钮或链接，不需要自定义 ARIA 角色。</li><li>页面导航到全新空页面时，文档标题和主标题说明范围。</li><li>同页筛选后出现零结果时，以 <code>status</code> 或等价机制宣布简短结果，不移动焦点。</li><li>权限或错误需要用户立即处理时，根据严重性和上下文选择错误模式，不把所有状态设为 assertive live region。</li><li>插图是装饰时使用空文本替代；有信息时正文必须表达同等事实。</li><li>操作顺序符合视觉与阅读顺序，200% 文本缩放下不重叠。</li></ul><h2 id="国际化与内容边界" tabindex="-1">国际化与内容边界 <a class="header-anchor" href="#国际化与内容边界" aria-label="Permalink to &quot;国际化与内容边界&quot;">​</a></h2><ul><li>数量使用本地化格式和正确复数规则。</li><li>日期范围明确时区和包含边界。</li><li>动作标签描述结果，如“清除筛选”，不用“好的”“继续”。</li><li>德语等长文本、中文无空格换行和从右到左布局都要验证。</li><li>不用带文化含义的插图表达成功、失败或权限。</li></ul><h2 id="观测与诊断" tabindex="-1">观测与诊断 <a class="header-anchor" href="#观测与诊断" aria-label="Permalink to &quot;观测与诊断&quot;">​</a></h2><h3 id="观测信号" tabindex="-1">观测信号 <a class="header-anchor" href="#观测信号" aria-label="Permalink to &quot;观测信号&quot;">​</a></h3><p>按空状态原因分别统计：</p><ul><li>首次使用到首项成功创建的比例和时间。</li><li>筛选无结果后清除、改单项、离开和再次搜索。</li><li>已清空状态进入归档、恢复或新建。</li><li>权限状态中的申请、返回和重复访问。</li><li>错误被误分类为零结果的监控告警。</li><li>空页、游标过期和索引延迟发生率。</li></ul><p>不要把所有 Empty State 汇总成一个曝光事件。不同原因的合理行为完全不同。</p><h3 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h3><ol><li>固定主体、组织、对象范围和权限。</li><li>记录原始查询、当前筛选和游标。</li><li>检查请求状态与响应新鲜度。</li><li>对比匹配计数和同权限基础计数。</li><li>检查前置配置与集合生命周期。</li><li>检查客户端缓存是否覆盖权威结果。</li><li>复测动态状态消息和焦点。</li></ol><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>查询返回空数组但总数大于零。</li><li>当前页数据全部被另一用户删除。</li><li>权限在请求期间撤销。</li><li>搜索索引延迟但权威数据存在。</li><li>创建成功后列表查询暂时读不到。</li><li>用户从多筛选 URL 直接进入。</li><li>导入了一部分数据但后台任务失败。</li><li>断网后应用仍有过期缓存。</li></ol><p>每次确认界面没有把未知结果写成确定空。</p><h2 id="综合练习-建立空状态决策系统" tabindex="-1">综合练习：建立空状态决策系统 <a class="header-anchor" href="#综合练习-建立空状态决策系统" aria-label="Permalink to &quot;综合练习：建立空状态决策系统&quot;">​</a></h2><p>为一个同时支持创建、导入、筛选、归档和角色权限的集合页面交付：</p><ol><li>空状态原因枚举与判定顺序。</li><li>服务端数据和能力契约。</li><li>首次使用、筛选无结果、已清空、权限、错误和加载界面。</li><li>每种状态的标题、说明、主操作和退出条件。</li><li>并发删除、索引延迟、权限撤销与分页越界测试。</li><li>无障碍状态消息与生产观测方案。</li></ol><p>验收标准：</p><ul><li><code>items.length === 0</code> 不是唯一判定条件。</li><li>无权限、错误和加载不会显示成“暂无数据”。</li><li>主要操作能直接改变当前空状态。</li><li>筛选条件和范围不会在零结果时消失。</li><li>计数、搜索建议和对象存在性遵守权限边界。</li><li>创建或恢复后由权威结果退出空状态。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://carbondesignsystem.com/patterns/empty-states-pattern/" target="_blank" rel="noreferrer">IBM Carbon Design System：Empty States</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/WCAG22/working-examples/failure-status-message/" target="_blank" rel="noreferrer">W3C WAI：Failure Example — Search Results Without a Status Role</a>（访问日期：2026-07-18）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html" target="_blank" rel="noreferrer">RFC 9110：HTTP Semantics</a>（访问日期：2026-07-18）</li></ul>`,136)])])}const b=t(s,[["render",n]]);export{c as __pageData,b as default};
